// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PostingBoard {
    struct Post {
        address author;
        string content;
        uint256 totalPower;
    }

    Post[] private _posts;
    mapping(address => uint256) private _authorBalances;

    event PostCreated(uint256 indexed postId, address indexed author, string content);
    event PostBoosted(uint256 indexed postId, address indexed booster, uint256 amount);
    event Withdrawn(address indexed author, uint256 amount);

    function postCount() public view returns (uint256) {
        return _posts.length;
    }

    function posts(uint256 postId) public view returns (address author, string memory content, uint256 totalPower) {
        Post storage post = _posts[postId];
        return (post.author, post.content, post.totalPower);
    }

    function createPost(string calldata content) external returns (uint256) {
        require(bytes(content).length > 0, "Empty content");
        uint256 postId = _posts.length;
        _posts.push(Post({author: msg.sender, content: content, totalPower: 0}));
        emit PostCreated(postId, msg.sender, content);
        return postId;
    }

    function boostPost(uint256 postId) external payable {
        require(_posts.length > postId, "Post does not exist");
        require(msg.value > 0, "No ether provided");
        Post storage post = _posts[postId];
        _authorBalances[post.author] += msg.value;
        post.totalPower += msg.value;
        emit PostBoosted(postId, msg.sender, msg.value);
    }

    function authorBalances(address author) public view returns (uint256) {
        return _authorBalances[author];
    }

    function withdraw() external {
        uint256 amount = _authorBalances[msg.sender];
        _authorBalances[msg.sender] = 0;
        (bool sent, ) = msg.sender.call{value: amount}("");
        require(sent, "Failed to send Ether");
        emit Withdrawn(msg.sender, amount);
    }
}
